N-gramas por código
Vocabulário recorrente dentro de cada categoria analítica. Bigrams e trigrams revelam as expressões-chave que caracterizam cada argumento no corpus.

viewof selectedCode = Inputs.select(
  data.ngrams.map(d =&gt; d.code),
  {
    label: "Código analítico",
    format: d =&gt; {
      const entry = data.ngrams.find(x =&gt; x.code === d)
      return `${d} (${entry ? entry.n : ""} segmentos)`
    }
  }
)







{
  const entry = data.ngrams.find(d =&gt; d.code === selectedCode)
  if (!entry) return html`&lt;p&gt;Selecione um código.&lt;/p&gt;`

  const col = getColor(selectedCode)
  const maxB = entry.bigrams.length &gt; 0 ? entry.bigrams[0][2] : 1
  const maxT = entry.trigrams.length &gt; 0 ? entry.trigrams[0][3] : 1

  const bigramRows = entry.bigrams.map(([w1, w2, n]) =&gt; {
    const pct = Math.round(n / maxB * 100)
    return html`&lt;div style="display:flex;align-items:center;gap:8px;margin-bottom:5px;"&gt;
      &lt;div style="flex:1;font-size:13px;"&gt;
        &lt;span style="background:#F0EEE8;border-radius:4px;padding:2px 7px;"&gt;${w1}&lt;/span&gt;
        &lt;span style="color:#888;font-size:11px;margin:0 2px;"&gt;+&lt;/span&gt;
        &lt;span style="background:#F0EEE8;border-radius:4px;padding:2px 7px;"&gt;${w2}&lt;/span&gt;
      &lt;/div&gt;
      &lt;div style="width:100px;height:8px;background:#EEECE6;border-radius:99px;overflow:hidden;"&gt;
        &lt;div style="width:${pct}%;height:100%;background:${col};opacity:0.7;border-radius:99px;"&gt;&lt;/div&gt;
      &lt;/div&gt;
      &lt;div style="width:20px;font-size:12px;color:#888;text-align:right;"&gt;${n}&lt;/div&gt;
    &lt;/div&gt;`
  })

  const trigramRows = entry.trigrams.map(([w1, w2, w3, n]) =&gt; {
    const pct = Math.round(n / maxT * 100)
    return html`&lt;div style="display:flex;align-items:center;gap:8px;margin-bottom:5px;"&gt;
      &lt;div style="flex:1;font-size:13px;"&gt;
        &lt;span style="background:#F0EEE8;border-radius:4px;padding:2px 7px;"&gt;${w1}&lt;/span&gt;
        &lt;span style="color:#888;font-size:11px;margin:0 2px;"&gt;·&lt;/span&gt;
        &lt;span style="background:#F0EEE8;border-radius:4px;padding:2px 7px;"&gt;${w2}&lt;/span&gt;
        &lt;span style="color:#888;font-size:11px;margin:0 2px;"&gt;·&lt;/span&gt;
        &lt;span style="background:#F0EEE8;border-radius:4px;padding:2px 7px;"&gt;${w3}&lt;/span&gt;
      &lt;/div&gt;
      &lt;div style="width:100px;height:8px;background:#EEECE6;border-radius:99px;overflow:hidden;"&gt;
        &lt;div style="width:${pct}%;height:100%;background:${col};opacity:0.7;border-radius:99px;"&gt;&lt;/div&gt;
      &lt;/div&gt;
      &lt;div style="width:20px;font-size:12px;color:#888;text-align:right;"&gt;${n}&lt;/div&gt;
    &lt;/div&gt;`
  })

  return html`&lt;div style="display:grid;grid-template-columns:1fr 1fr;gap:2rem;margin-top:1rem;"&gt;
    &lt;div&gt;
      &lt;div style="font-size:11px;font-weight:500;color:#888;text-transform:uppercase;letter-spacing:.05em;margin-bottom:10px;"&gt;Bigrams&lt;/div&gt;
      ${bigramRows}
    &lt;/div&gt;
    &lt;div&gt;
      &lt;div style="font-size:11px;font-weight:500;color:#888;text-transform:uppercase;letter-spacing:.05em;margin-bottom:10px;"&gt;Trigrams&lt;/div&gt;
      ${trigramRows}
    &lt;/div&gt;
  &lt;/div&gt;`
}







