Documentos
Cards clicáveis por PL/PDL. Cor da borda indica polaridade dominante. Clique em um documento para ver a distribuição de códigos.

viewof selectedDoc = {
  const container = html`&lt;div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(150px,1fr));gap:8px;margin-bottom:1.5rem;"&gt;&lt;/div&gt;`
  let current = null

  const sorted = data.doc_polarity.slice().sort((a,b) =&gt; b.total - a.total)
  sorted.forEach(d =&gt; {
    const pol = d.polarity
    const borderColor = pol === "pro" ? "#1D9E75" : pol === "contra" ? "#D85A30" : "#888780"
    const label = pol === "pro" ? "pró DSR" : pol === "contra" ? "contra DSR" : "neutro"

    const card = html`&lt;div style="border:0.5px solid #ccc;border-left:3px solid ${borderColor};border-radius:6px;padding:10px 12px;cursor:pointer;"&gt;
      &lt;div style="font-size:12px;font-weight:500;margin-bottom:4px;"&gt;${d.doc}&lt;/div&gt;
      &lt;div style="font-size:11px;color:#888;"&gt;${d.total} seg. · ${label}&lt;/div&gt;
    &lt;/div&gt;`

    card.addEventListener("click", () =&gt; {
      if (current) current.style.background = ""
      card.style.background = "rgba(0,0,0,0.05)"
      current = card
      container.value = d.doc
      container.dispatchEvent(new Event("input"))
    })
    container.appendChild(card)
  })

  container.value = null
  return container
}







{
  if (!selectedDoc) return html`&lt;p style="color:#888;font-size:13px;"&gt;Clique em um documento para ver os detalhes.&lt;/p&gt;`

  const codes = data.doc_codes[selectedDoc]
  if (!codes || codes.length === 0) return html`&lt;p style="color:#888;font-size:13px;"&gt;Sem dados para este documento.&lt;/p&gt;`

  const maxN = codes[0].n
  const rows = codes.map(d =&gt; {
    const col = getColor(d.code)
    const pct = Math.round(d.n / maxN * 100)
    return html`&lt;div style="display:flex;align-items:center;gap:8px;margin-bottom:6px;"&gt;
      &lt;div style="flex:1;font-size:13px;"&gt;${d.code}&lt;/div&gt;
      &lt;div style="width:120px;height:8px;background:#EEECE6;border-radius:99px;overflow:hidden;"&gt;
        &lt;div style="width:${pct}%;height:100%;background:${col};opacity:0.8;border-radius:99px;"&gt;&lt;/div&gt;
      &lt;/div&gt;
      &lt;div style="width:20px;font-size:12px;color:#888;text-align:right;"&gt;${d.n}&lt;/div&gt;
    &lt;/div&gt;`
  })

  return html`&lt;div style="margin-top:0.5rem;"&gt;
    &lt;div style="font-size:14px;font-weight:500;margin-bottom:12px;"&gt;${selectedDoc}&lt;/div&gt;
    ${rows}
  &lt;/div&gt;`
}

